import React from 'react';
import Navbar from './Navbar';
import Sidebar from './Sidebar';
import './MainLayout.css';

/**
 * App shell: fixed sidebar + sticky navbar; children = existing dashboard markup (unchanged).
 */
export default function MainLayout({ children, activeNavId = 'dashboards' }) {
  return (
    <div className="main-layout">
      <Sidebar activeNavId={activeNavId} />
      <div className="main-layout__column">
        <Navbar />
        <div className="main-layout__content">{children}</div>
      </div>
    </div>
  );
}
